	scanf("%d%d", &n, &k);

	if (k == 1) {

		printf("1\n");

		return 0;

	}

	ll ans = 1;

	for (int i = 1; i <= k - 1; ++i) {

		ans = ans * i % mod;

	}

	for (int i = n - k + 1; i <= n; ++i) {

		ans = ans * i % mod;

	}

	printf("%lld\n", ans);

	return 0;

}

